use std::io;

fn main() {
    let mut buffer = String::new();
    io::stdin().read_line(&mut buffer).expect("failed to read input");
    let s: u32 = buffer.trim().parse().expect("invalid input");

    println!("{}", 2 * (s / 3) + if s % 3 != 0 { 1 } else { 0 });
}
